package org.apache.commons.lang3.text.translate;

import java.io.IOException;
import java.io.Writer;
import java.util.HashMap;

/**
 * Translates a value using a lookup table.
 *
 * @since 3.0
 * @version $Id$
 */
public class LookupTranslator extends CharSequenceTranslator {

    private final HashMap<CharSequence, CharSequence> translationMap;
    private final int minLength;
    private final int maxLength;

    /**
     * Define the lookup table to be used in translation
     *
     * Note that, as of Lang 3.1, the key to the lookup table is converted to a 
     * java.lang.String, while the value remains as a java.lang.CharSequence. 
     * This is because we need the key to support hashCode and equals(Object), 
     * allowing it to be the key for a HashMap. See LANG-882.
     *
     * @param lookup CharSequence[][] table of size [*][2]
     */
    public LookupTranslator(final CharSequence[]... lookup) {
        translationMap = new HashMap<CharSequence, CharSequence>();
        int tempMin = Integer.MAX_VALUE;
        int tempMax = 0;
        if (lookup != null) {
            for (CharSequence[] sequenceArray : lookup) {
                this.translationMap.put(sequenceArray[0], sequenceArray[1]);
                int currentLength = sequenceArray[0].length();
                if (currentLength < tempMin) {
                    tempMin = currentLength;
                }
                if (currentLength > tempMax) {
                    tempMax = currentLength;
                }
            }
        }
        minLength = tempMin;
        maxLength = tempMax;
    }

    /**
     * {@inheritDoc}
     */
    @Override
    public int translate(final CharSequence input, final int index, final Writer out) throws IOException {
        int upperLimit = maxLength;
        if (index + maxLength > input.length()) {
            upperLimit = input.length() - index;
        }
        // descend so as to get a greedy algorithm
        int j = upperLimit;
        while (j >= minLength) {
            CharSequence substring = input.subSequence(index, index + j);
            CharSequence translation = translationMap.get(substring);
            if (translation != null) {
                out.write(translation.toString());
                return j;
            }
            j--;
        }
        return 0;
    }
}
